form:Form.form:Scripts:
		var CFG;
var TIT=null;

var g_objEdit=new Array();

function InitEditorOnChange(objEdit) { InitEditor("o_onchange", objEdit); }
function InitEditorOnValidate(objEdit) { InitEditor("o_onvalidate", objEdit); }
function InitEditor(ctrlName, objEdit)
{
 	//Agrego el CODIGO                             
 	objEdit.SetText(Ctrl(ctrlName).GetXValue());
 	objEdit.ReadOnly();

 	g_objEdit[ctrlName]=objEdit;
}       

function EditEventoOnChange() { EditEventoName("o_onchange"); }
function EditEventoOnValidate() { EditEventoName("o_onvalidate"); }
function EditEventoName(ctrlName)
{
	var PARAM=new NomadXML("PARAM");                                           
	PARAM.SetAttr("oi_form", Ctrl("PARENT").GetXValue()); 
	PARAM.SetAttr("o_scripts_1", Ctrl(ctrlName).GetXValue());
	openNewFlowWait("NucleusWF.Base.Definicion.Workflows.FORM.flow","EditEvent",PARAM.ToString(),new objRefresh(ctrlName), "L");
}

function objRefresh(ctrlName)
{                           
	this.ctrlName=ctrlName;                        
	this.processResult = function(xml)
	{
		var PARAM=new NomadXML(xml);
		if (PARAM.GetAttr("ACTION")=="ACCEPT")
		{
			Ctrl(this.ctrlName).SetXValue(PARAM.GetAttr("o_scripts_1"));
			g_objEdit[this.ctrlName].SetText(PARAM.GetAttr("o_scripts_1"));
		}
	}
}



function SAVE()
{

	//Si el control NO ES BOTON valida que la variable sea distinta que la variable padre
	if (Ctrl('main').GetMode() != "BUT_ADD" && Ctrl('main').GetMode() != "BUT_EDIT") {
		if(Ctrl("c_var").GetXValue() == Ctrl("c_parent_field").GetXValue()) {
			alert("La variable y la variable padre no pueden ser iguales.");
			return false;
		}
	}

	if(Ctrl('main').GetMode() == "BUT_ADD" || Ctrl('main').GetMode() == "BUT_EDIT")	
	{
		Ctrl('d_param_1').SetXValue(Ctrl('imagen').GetCValue());
		if(Ctrl('c_mode').GetXValue() == "AF" && Ctrl('o_onchange').GetXValue() == "")
		{
			alert("Debe completar la función OnClick.");
			return false;
		}
	}
	if((Ctrl('main').GetMode() == "BUT_ADD" && Ctrl('c_var').GetXValue() != "") || (Ctrl('main').GetMode() == "BUT_EDIT" && Ctrl('c_var').GetXValue() != ""))
		if(Ctrl('c_valor').GetXValue() == "" && Ctrl('c_mode').GetXValue() == "A")
		{
			alert("Debe completar el valor al hacer click.");			
			return false;
		}

	//Valida caracteres especiales.
	var errorMessage = "El código no acepta alguno de los caracteres ingresados.";
  if(/(^([0-9,_,a-zA-Z])*$)/.test(Ctrl('c_field').GetXValue()))
  {
      Ctrl('main').DoEvent("SAVE");
  } 
  else 
  {
  	alert(errorMessage);
    return false;
  }
	//Ctrl('main').DoEvent("SAVE");
}
function ReplaceResource(recID) {
	var recValue=Ctrl("main").getResource(recID);
	recValue=Replace(recValue,"#RESOURCE-LIST#"  ,CFG.GetAttr("RESOURCE-LIST"  ));
	recValue=Replace(recValue,"#RESOURCE-ID#"    ,CFG.GetAttr("RESOURCE-ID"    ));
	recValue=Replace(recValue,"#RESOURCE-PARENT#",CFG.GetAttr("RESOURCE-PARENT"));
	recValue=Replace(recValue,"#RESOURCE-OBJECT#",CFG.GetAttr("RESOURCE-OBJECT"));

	Ctrl("main").setResource(recValue, recID);
}

function RefreshReport() {
	//Actualiza el reporte del formulario
	var strURL;

	strURL = "../../../ReportViewer.aspx?file=NucleusWF.Base.Definicion.WFPLA_Main.rpt" +
					"&ut=" + GetProxy().UserToken() +
					"&id=" + Ctrl("PARENT").GetXValue() +
					"&now=" + datetime2str(new Date());

	Ctrl("REPORT_ORG").SetURL(strURL);
}

///////////////////////////////////////////////////////////////////////////////          
//CONTEXTS MENUES

function CTRLCxMenu(pOI, pEvent) {
	Ctrl("GroupField_CM").SetXValue(pOI);
	Ctrl("GroupField_CM").OnContextMenu(pEvent);
}

function MainGroupCxMenu(pOI, pEvent) {
	Ctrl("MainGroup_CM").SetXValue(pOI);
	Ctrl("MainGroup_CM").OnContextMenu(pEvent);
}

function FormCxMenu(pOI, pEvent) {
	Ctrl("MainGroup_CM").SetXValue(pOI);
	Ctrl("MainGroup_CM").OnContextMenu(pEvent);
}


function FlowResult() {
	this.processResult = function(xml) {
		RefreshReport();
	}
}

