//GroupField --------------------
function GroupField_Edit(pObj) {

}

function GroupField_Del(pObj) {
	if (confirm("¿Está seguro que desea eliminar el control?"))
		openNewFlowWait("NucleusWF.Base.Definicion.Workflows.FORM.flow", "FieldDelete", '<PARAM oi_field="'+pObj.GetXValue()+'" />', new FlowResult(), "L");
}

function GroupField_Up(pObj) {
	openNewFlowWait("NucleusWF.Base.Definicion.Workflows.FORM.flow", "FieldUpDown", '<PARAM oi_field="'+pObj.GetXValue()+'" direction="UL"/>', new FlowResult(), "L");
}

function GroupField_Down(pObj) {
	openNewFlowWait("NucleusWF.Base.Definicion.Workflows.FORM.flow", "FieldUpDown", '<PARAM oi_field="'+pObj.GetXValue()+'" direction="DR"/>', new FlowResult(), "L");
}

